// ═════════════════════════════════════════════════════════════════════════════
// DURABLE NATIVE STORAGE
// localStorage in an iOS WKWebView is NOT durable — iOS can evict it under storage
// pressure, which would wipe a user's local workout state. This layer makes the app's
// state survive that by mirroring every localStorage write to the native Capacitor
// Preferences store (real on-device storage), and restoring from it at launch.
//
// Design choice (deliberately low-risk): the app keeps using synchronous `localStorage`
// exactly as before — we don't touch the ~30 call sites. We just (1) hydrate localStorage
// from native Preferences ONCE at startup (before React renders), and (2) transparently
// mirror writes/removes to native in the background by wrapping setItem/removeItem.
// If Preferences is empty on first run (existing users), localStorage already has their
// data and we seed Preferences from it — so nothing is ever lost in the transition.
// ═════════════════════════════════════════════════════════════════════════════
function nativePrefs() {
  const Cap = (typeof window !== "undefined") ? window.Capacitor : null;
  if (Cap?.isNativePlatform?.() && Cap.Plugins?.Preferences) return Cap.Plugins.Preferences;
  return null;
}

// Keys we mirror to native storage. We only persist the app's real state — not transient
// caches. (Anything not listed still works in localStorage; it just isn't durably backed.)
const DURABLE_PREFIX = "seshd_";

// Install the write-through mirror ONCE. After this, every localStorage.setItem/removeItem
// for a seshd_* key also updates native storage. Idempotent.
let __mirrorInstalled = false;
function installStorageMirror() {
  if (__mirrorInstalled || typeof window === "undefined" || !window.localStorage) return;
  if (!nativePrefs()) return; // web build / not native — plain localStorage is fine
  __mirrorInstalled = true;
  const origSet = localStorage.setItem.bind(localStorage);
  const origRemove = localStorage.removeItem.bind(localStorage);
  localStorage.setItem = function (key, value) {
    origSet(key, value);
    if (typeof key === "string" && key.startsWith(DURABLE_PREFIX)) {
      try { nativePrefs()?.set({ key, value: String(value) }).catch(() => {}); } catch {}
    }
  };
  localStorage.removeItem = function (key) {
    origRemove(key);
    if (typeof key === "string" && key.startsWith(DURABLE_PREFIX)) {
      try { nativePrefs()?.remove({ key }).catch(() => {}); } catch {}
    }
  };
}

// Hydrate localStorage from native Preferences at startup. MUST be awaited before the app
// reads localStorage (i.e. before React mounts) so loadStore()/loadSession() see real data.
// - If native has data: copy it into localStorage (this is the durable source of truth).
// - If native is empty but localStorage has data (existing user's first run on this build):
//   seed native from localStorage so it's protected from here on.
// Exported so the app entry (main.jsx) can `await hydrateFromNative()` BEFORE mounting React,
// ensuring localStorage is populated from durable native storage before loadStore() runs.
export { hydrateFromNative };

async function hydrateFromNative() {
  const P = nativePrefs();
  if (!P) return; // web / non-native — localStorage is already the store
  try {
    const { keys } = await P.keys();
    const nativeKeys = (keys || []).filter(k => typeof k === "string" && k.startsWith(DURABLE_PREFIX));
    if (nativeKeys.length > 0) {
      // Native is the source of truth — pull everything into localStorage.
      for (const key of nativeKeys) {
        try {
          const { value } = await P.get({ key });
          if (value != null) localStorage.setItem(key, value);
        } catch {}
      }
    } else {
      // First run with native storage available — seed it from whatever localStorage has.
      try {
        for (let i = 0; i < localStorage.length; i++) {
          const key = localStorage.key(i);
          if (key && key.startsWith(DURABLE_PREFIX)) {
            const value = localStorage.getItem(key);
            if (value != null) await P.set({ key, value });
          }
        }
      } catch {}
    }
  } catch {}
  // Install the write-through mirror AFTER hydration so we don't echo during restore.
  installStorageMirror();
}


const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const SUPABASE_KEY = import.meta.env.VITE_SUPABASE_ANON_KEY;
const IS_DEV = !!(import.meta.env && import.meta.env.DEV); // true in `vite dev`, false in production builds
const NAV_CLEARANCE = "calc(86px + env(safe-area-inset-bottom))"; // bottom-padding so scrollable content clears the floating bottom nav overlay
const devWarn = (...args) => { if (IS_DEV) console.warn(...args); };
const devError = (...args) => { if (IS_DEV) console.error(...args); };

// ── Analytics (PostHog) ────────────────────────────────────────────────────────
// No-op until VITE_POSTHOG_KEY is set in Vercel env vars. We send behavioral
// events only (signup, workout logged, post created, tab switches) — never
// workout content, photos, or messages — to keep this purely usage analytics.
const POSTHOG_KEY = import.meta.env.VITE_POSTHOG_KEY || "";
function track(event, props = {}) {
  try {
    if (!POSTHOG_KEY || typeof window === "undefined" || !window.posthog) return;
    window.posthog.capture(event, props);
  } catch (e) {}
}
function identifyUser(userId) {
  try {
    if (!POSTHOG_KEY || typeof window === "undefined" || !window.posthog || !userId) return;
    window.posthog.identify(userId);
  } catch (e) {}
}

// ── OAuth provider flags ──────────────────────────────────────────────────────
// Flip a provider to true ONLY after it's fully configured in Supabase
// (Auth → Providers). An unconfigured provider renders a login button that fails
// on tap — App Review taps every button, and a dead login is a rejection.
const OAUTH_ENABLED = { apple: false, google: false };

// Lightweight Supabase client — no npm package needed
const sb = (() => {
  const headers = {
    "apikey": SUPABASE_KEY,
    "Authorization": `Bearer ${SUPABASE_KEY}`,
    "Content-Type": "application/json",
    "Prefer": "return=representation",
  };

  function authHeaders(token) {
    if (!token) return headers;
    return { ...headers, "Authorization": `Bearer ${token}` };
  }

  async function query(path, opts = {}, token = null) {
    const { headers_extra, timeout, ...fetchOpts } = opts;
    const mergedHeaders = { ...authHeaders(token), ...(headers_extra || {}) };
    // Hard timeout so a stalled connection can never hang a screen forever
    // (e.g. the Messages list spinning indefinitely on a flaky network).
    const ctrl = new AbortController();
    const to = setTimeout(() => ctrl.abort(), timeout || 20000);
    let res;
    try {
      res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
        headers: mergedHeaders,
        signal: ctrl.signal,
        ...fetchOpts,
      });
    } finally {
      clearTimeout(to);
    }
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.message || res.statusText);
    }
    const text = await res.text();
    return text ? JSON.parse(text) : null;
  }

  async function rpc(fn, params = {}, token = null) {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/rpc/${fn}`, {
      method: "POST",
      headers: authHeaders(token),
      body: JSON.stringify(params),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.message || res.statusText);
    }
    const text = await res.text();
    return text ? JSON.parse(text) : null;
  }

  // Auth helpers
  async function signUp(email, password, username, name) {
    const res = await fetch(`${SUPABASE_URL}/auth/v1/signup`, {
      method: "POST",
      headers,
      body: JSON.stringify({
        email, password,
        data: { username, name }
      }),
    });
    const data = await res.json();
    if (data.error) throw new Error(data.error.message || data.msg || "Signup failed");
    return data;
  }

  async function signIn(emailOrUsername, password) {
    // Username login: look up email from profiles table (we store it there for this purpose).
    let email = emailOrUsername.trim();
    if (!email.includes("@")) {
      try {
        const rows = await fetch(
          `${SUPABASE_URL}/rest/v1/profiles?username=eq.${encodeURIComponent(email.toLowerCase())}&select=email`,
          { headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` } }
        ).then(r => r.json());
        const found = rows?.[0]?.email;
        if (!found) throw new Error("No account found with that username.");
        email = found;
      } catch (e) { throw e; }
    }
    const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
      method: "POST",
      headers,
      body: JSON.stringify({ email, password }),
    });
    const data = await res.json().catch(() => ({}));
    // Supabase returns auth errors in several shapes (error_description / error / msg / error_code)
    // and a non-2xx status. Catch all of them, and require an access_token, so a failed login
    // surfaces as a clear error instead of falling through to a hung "setting up" screen.
    if (!res.ok || data.error || data.error_description || data.msg || !data.access_token) {
      const raw = data.error_description || data.msg || data.error || "";
      const friendly = /invalid login credentials/i.test(raw)
        ? "Incorrect email or password."
        : (raw || "Sign in failed. Please try again.");
      throw new Error(friendly);
    }
    return data; // { access_token, refresh_token, user }
  }

  async function signOut(token) {
    await fetch(`${SUPABASE_URL}/auth/v1/logout`, {
      method: "POST",
      headers: authHeaders(token),
    });
  }

  async function refreshToken(refresh_token) {
    const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=refresh_token`, {
      method: "POST",
      headers,
      body: JSON.stringify({ refresh_token }),
    });
    const data = await res.json();
    if (data.error) throw new Error(data.error_description || "Session expired");
    return data;
  }

  // OAuth: start the flow by redirecting to Supabase's authorize endpoint
  function signInWithOAuth(provider) {
    const redirectTo = encodeURIComponent(window.location.origin + window.location.pathname);
    const url = `${SUPABASE_URL}/auth/v1/authorize?provider=${provider}&redirect_to=${redirectTo}`;
    window.location.href = url;
  }

  // Sign in with Apple. On the native iOS build we use the Capacitor Sign in with Apple plugin —
  // the system sheet Apple's App Store guideline 4.8 requires when any social login ships — and
  // exchange the returned identity token with Supabase (grant_type=id_token). Reached through the
  // runtime Capacitor global (same pattern as Haptics/Health/LiveActivity) so there's no build-time
  // import and the web bundle stays clean. On web/PWA there's no native sheet, so we fall back to
  // the hosted OAuth redirect flow, which AppInner's init() completes by parsing #access_token on
  // return. NOTE: the native id_token path can only be exercised on a real device once Ashley adds
  // the "Sign in with Apple" capability + the plugin pod in Xcode — verify it there before submit.
  async function signInWithApple() {
    const Cap = (typeof window !== "undefined") ? window.Capacitor : null;
    const Plugin = Cap?.isNativePlatform?.() ? Cap.Plugins?.SignInWithApple : null;
    if (Plugin?.authorize) {
      // A nonce ties this request to the device session; Apple embeds it in the signed token so
      // Supabase can reject a replayed token. Pass the same raw value to Supabase for verification.
      const nonce = (typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : String(Math.random())).replace(/-/g, "");
      const result = await Plugin.authorize({ scopes: "name email", nonce });
      const idToken = result?.response?.identityToken;
      if (!idToken) throw new Error("Apple sign-in was cancelled.");
      const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=id_token`, {
        method: "POST",
        headers,
        body: JSON.stringify({ provider: "apple", id_token: idToken, nonce }),
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.access_token) {
        throw new Error(data.error_description || data.msg || data.error || "Apple sign-in failed.");
      }
      return data; // { access_token, refresh_token, user } — caller saves the session
    }
    // Web fallback: hosted redirect flow (no session returned here; init() picks it up on return).
    signInWithOAuth("apple");
    return null;
  }

  // ── UNIVERSAL WRITE-RETRY QUEUE ───────────────────────────────────────────
  // Wraps a server write so that if it fails due to being OFFLINE (network error), the write is
  // saved to a durable queue and replayed on reconnect — instead of being silently lost. Only
  // idempotent "set" writes (PATCH / DELETE) are queued: replaying them is safe (last-write-wins),
  // whereas replaying a POST could double-insert. Validation/auth errors (4xx) are NOT queued — the
  // write is bad and would retry forever — they reject so the caller can handle them.
  const WRITE_QUEUE_KEY = "seshd_write_queue";
  const WRITE_QUEUE_CAP = 200; // small idempotent PATCH/DELETE bodies; 200 is ample headroom
  const readQueue = () => { try { return JSON.parse(localStorage.getItem(WRITE_QUEUE_KEY) || "[]"); } catch { return []; } };
  const writeQueue = (q) => {
    try {
      if (q.length > WRITE_QUEUE_CAP) devWarn(`writeQueue: dropping ${q.length - WRITE_QUEUE_CAP} oldest unsynced write(s) over cap ${WRITE_QUEUE_CAP}`);
      localStorage.setItem(WRITE_QUEUE_KEY, JSON.stringify(q.slice(-WRITE_QUEUE_CAP)));
    } catch {}
  };

  // A failed fetch (offline / DNS / connection) throws a TypeError; a 4xx/5xx comes back as an
  // Error we threw with a message. We treat only the thrown-fetch case as "retryable offline".
  async function queueWrite(path, opts = {}, token = null) {
    const method = (opts.method || "GET").toUpperCase();
    const retryable = method === "PATCH" || method === "DELETE" || method === "PUT";
    try {
      return await query(path, opts, token);
    } catch (e) {
      const offline = (typeof navigator !== "undefined" && navigator.onLine === false)
        || (e && e.name === "TypeError"); // fetch failed = network down
      if (offline && retryable) {
        const q = readQueue();
        // Same row (path) + PATCH: merge the partial bodies so changing two settings offline (e.g.
        // theme AND unit) doesn't lose one — both fields end up in a single queued PATCH. For
        // DELETE/PUT, last-write-wins replacement is correct.
        const existingIdx = q.findIndex(item => item.path === path && item.method === method);
        if (existingIdx >= 0 && method === "PATCH") {
          try {
            const merged = { ...JSON.parse(q[existingIdx].body || "{}"), ...JSON.parse(opts.body || "{}") };
            q[existingIdx] = { ...q[existingIdx], body: JSON.stringify(merged), ts: Date.now() };
            writeQueue(q);
            return null;
          } catch { /* fall through to replace if bodies aren't JSON */ }
        }
        const filtered = q.filter(item => !(item.path === path && item.method === method));
        filtered.push({ path, method, body: opts.body || null, headers_extra: opts.headers_extra || null, ts: Date.now() });
        writeQueue(filtered);
        return null; // resolve gracefully — the optimistic local update already happened
      }
      throw e; // real error (validation/auth) — let the caller deal with it
    }
  }

  // Replay queued writes in order. Called on reconnect. Stops on the first hard failure so order is
  // preserved; offline failures re-queue. Token is resolved fresh by the caller.
  async function flushWriteQueue(token) {
    let q = readQueue();
    if (!q.length || !token) return { flushed: 0, remaining: q.length };
    let flushed = 0;
    const remaining = [];
    for (const item of q) {
      try {
        await query(item.path, { method: item.method, body: item.body, headers_extra: item.headers_extra }, token);
        flushed++;
      } catch (e) {
        const offline = (typeof navigator !== "undefined" && navigator.onLine === false) || (e && e.name === "TypeError");
        if (offline) { remaining.push(item); } // still offline — keep for next time
        // else: hard error — drop it (a doomed write shouldn't block the queue forever)
      }
    }
    writeQueue(remaining);
    return { flushed, remaining: remaining.length };
  }

  const queuedCount = () => readQueue().length;

  return { query, rpc, queueWrite, flushWriteQueue, queuedCount, signUp, signIn, signOut, refreshToken, signInWithOAuth, signInWithApple };
})();

// Upload image to Supabase Storage, return public URL
// Upload image via Edge Function proxy — bypasses iOS Safari CORS/Storage issues
// Downscale + recompress an image (base64 data URL) before upload. Phone photos are often
// 3-8MB; this caps the longest side at maxDim and re-encodes as JPEG, typically cutting size
// by 80-95%. Faster uploads on mobile data, smaller storage, snappier loads. Falls back to the
// original on any failure (e.g. canvas blocked) so upload still works.
function compressImage(base64DataUrl, maxDim = 1200, quality = 0.8) {
  return new Promise((resolve) => {
    try {
      const img = new Image();
      img.onload = () => {
        try {
          let { width, height } = img;
          if (width > maxDim || height > maxDim) {
            if (width >= height) { height = Math.round(height * (maxDim / width)); width = maxDim; }
            else { width = Math.round(width * (maxDim / height)); height = maxDim; }
          }
          const canvas = document.createElement("canvas");
          canvas.width = width; canvas.height = height;
          const ctx = canvas.getContext("2d");
          if (!ctx) { resolve(base64DataUrl); return; }
          ctx.drawImage(img, 0, 0, width, height);
          // JPEG drops transparency (fine for photos/avatars) and compresses well.
          const out = canvas.toDataURL("image/jpeg", quality);
          resolve(out && out.length > 20 ? out : base64DataUrl);
        } catch (err) { devWarn("compressImage: canvas/encode failed, using original", err); resolve(base64DataUrl); }
      };
      img.onerror = (err) => { devWarn("compressImage: image failed to load (CORS/format?), using original", err); resolve(base64DataUrl); };
      img.src = base64DataUrl;
    } catch (err) { devWarn("compressImage: unexpected failure, using original", err); resolve(base64DataUrl); }
  });
}

// Upload an image (base64 data URL) directly to Supabase Storage and return its public URL.
// Direct-to-Storage means NO Edge Function is required — just a public "images" bucket.
// Falls back to returning null on failure (callers keep the local preview / handle gracefully).
async function uploadImage(base64DataUrl, token, userId) {
  if (!base64DataUrl || !token) return null;
  try {
    // Compress/resize first (no-op fallback to original if it fails). Always JPEG after this.
    const compressed = await compressImage(base64DataUrl);
    const mime = compressed.match(/data:(.*?);/)?.[1] || "image/jpeg";
    const ext = mime.split("/")[1]?.split("+")[0] || "jpg";
    // base64 → binary blob
    const base64 = compressed.split(",")[1] || "";
    const binary = atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const blob = new Blob([bytes], { type: mime });
    // Unique path per user so uploads don't collide and RLS can scope by the user's folder.
    const path = `${userId || "anon"}/${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
    const res = await fetch(`${SUPABASE_URL}/storage/v1/object/images/${path}`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${token}`,
        "Content-Type": mime,
        "x-upsert": "true",
      },
      body: blob,
    });
    if (!res.ok) {
      const err = await res.text().catch(() => "");
      devWarn("uploadImage storage error:", res.status, err);
      return null;
    }
    // Public URL for the object (bucket must be public-read).
    return `${SUPABASE_URL}/storage/v1/object/public/images/${path}`;
  } catch (e) {
    devWarn("uploadImage failed:", e);
    return null;
  }
}


// Session storage
const SESSION_STORAGE_KEY = "seshd_session";
function loadSession() {
  try { return JSON.parse(localStorage.getItem(SESSION_STORAGE_KEY)); } catch { return null; }
}
function saveSession(s) {
  try { localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(s)); } catch {}
}
function clearSession() {
  try { localStorage.removeItem(SESSION_STORAGE_KEY); } catch {}
}

// Run an authed REST query; if it fails (most often an expired access token —
// the documented foreground-refresh race), refresh the session once and retry
// before giving up. Used by screens whose own access_token prop can go stale
// (Messages/Chat poll on intervals), so a dead token doesn't leave them empty.
async function queryWithRetry(path, opts, token) {
  const tok = token || loadSession()?.access_token;
  try {
    return await sb.query(path, opts, tok);
  } catch (e) {
    const saved = loadSession();
    if (!saved?.refresh_token) throw e;
    const fresh = await sb.refreshToken(saved.refresh_token);
    const merged = { ...saved, ...fresh };
    saveSession(merged);
    return await sb.query(path, opts, merged.access_token);
  }
}

