// Anatomical SVG icons — stylized body silhouettes with the target muscle highlighted
// 2D anatomical body-map — licensed Adobe Stock vector (per-muscle highlight, front + back).
// The artwork data (body + per-figure highlight paths) lives in a separate JSON that loads lazily
// the first time an exercise detail is opened, so it doesn't bloat the main bundle. The body is
// recolored to the theme and the worked muscle highlights in the app accent (light + dark aware).
const MUSCLE_FIGURE = {
  // app muscle value -> figure key in the body-map data
  "Chest":"Chest", "Back":"Back", "Lats":"Back", "Rear Delts":"Back", "Shoulders":"Shoulders",
  "Traps":"Back", "Biceps":"Arms", "Triceps":"Arms", "Quads":"Quadriceps", "Hamstrings":"Hamstring",
  "Glutes":"Glutes", "Calves":"Calves", "Core":"Abs", "Abs":"Abs", "Forearms":"Forearm",
  // Neck / Full Body / Cardio / Yoga have no single-muscle figure → plain body (no highlight)
};

// Two-shade anatomical body map. Primary muscle in the app accent, secondary muscles in a lighter
// tint, on male front + back figures side by side. Region paths are traced from a licensed anatomy
// chart (BODYMAP_MALE); per-exercise secondary muscles come from EXERCISE_SECONDARIES.
//
// BODYMAP_MALE/FEMALE + MUSCLE_ICONS (~165KB combined) live in their own module and load via
// dynamic import, not a static import, so they're not part of the initial bundle — they're
// only needed once a body-map/muscle-icon view actually renders. Every consumer below already
// has a graceful "no data yet" path (BodyMap falls back to MuscleIcon, MuscleIcon falls back to
// a drawn SVG, and every per-view lookup is a `if (!f) return null/""` guard) — so defaulting to
// an empty object while the import is in flight is safe everywhere, no new fallback UI needed.
let _bodyMapDataPromise = null;
let _bodyMapDataCache = null;
function loadBodyMapData() {
  if (!_bodyMapDataPromise) {
    _bodyMapDataPromise = import("./bodyMapData.js").then((m) => { _bodyMapDataCache = m; return m; });
  }
  return _bodyMapDataPromise;
}
function useBodyMapData() {
  const [data, setData] = useState(_bodyMapDataCache);
  useEffect(() => { if (!data) loadBodyMapData().then(setData); }, [data]);
  return data;
}
