// ═════════════════════════════════════════════════════════════════════════════
// STORAGE
// ═════════════════════════════════════════════════════════════════════════════
const SK = "seshd_v1";
// One-time cleanup of old localStorage keys no longer used.
// Safe to call on every load — the keys just get removed if present.
function cleanupStaleLocalStorage() {
  try {
    localStorage.removeItem("seshd_exercise_gifs_v1");
    localStorage.removeItem("seshd_exercise_gifs_v2");
    localStorage.removeItem("seshd_last_activity"); // replaced by seshd_seen_activity_count
  } catch {}
}
function loadStore() {
  cleanupStaleLocalStorage();
  const defaults = {
    users: [],
    posts: [],
    currentUserId: null,
    history: {},
    prs: {},
    prsE1rm: {},
    prsVolume: {},
    prEvents: [],
    programs: [],
    activeProgramId: null,
    notificationPrefs: { messages: true, kudos: true, comments: true, follows: true },
    defaultRestTime: 120,
    unit: "lbs",
    theme: "light",
    historyInteractions: {},
    workoutDates: {},
    blockedUsers: [],
    closeFriends: [], // user ids hand-picked for the Close Friends leaderboard (max 10, local-only v1)
    groups: [],
    weeklyTarget: 3, // default: 3 workouts/week for streak system
    dismissedInsights: [], // keys of insight cards the user swiped away (persisted)
    seenOnboarding: false,
    bodyLog: [], // body tracking entries: { id, date, weight, measurements:{}, photoData }
    customExercises: [], // user-created exercises: { id, name, muscle, equipment }
  };
  try {
    const r = localStorage.getItem(SK);
    if (r) {
      const d = JSON.parse(r);
      // Merge over defaults so a store saved by an OLDER app version (missing newer keys
      // like bodyLog/weeklyTarget) never has undefined collections that could crash.
      // Restore the cached feed so the app shows the last-loaded posts immediately (and offline),
      // then a fresh fetch replaces them when online. Avoids a blank feed with no connection.
      let cachedFeed = [];
      try { cachedFeed = JSON.parse(localStorage.getItem("seshd_feed_cache") || "[]") || []; } catch {}
      return { ...defaults, ...d, posts: cachedFeed };
    }
  } catch {}
  return defaults;
}
function saveStore(d) {
  // Don't persist the feed here — it's cached separately (seshd_feed_cache) and loadStore always
  // overrides posts with that cache, so the copy in this blob is dead weight that just inflates
  // every serialize. Stripping it shrinks the JSON we stringify on each save.
  const toSave = { ...d, posts: [] };
  try { localStorage.setItem(SK, JSON.stringify(toSave)); }
  catch (e) {
    // Most likely quota exceeded (progress photos are large base64 blobs). Retry without
    // photo data so weight/measurement history still persists rather than losing everything.
    try {
      const trimmed = { ...toSave, bodyLog: (toSave.bodyLog || []).map(b => ({ ...b, photoData: null })) };
      localStorage.setItem(SK, JSON.stringify(trimmed));
    } catch {}
  }
}

